     1→/**
     2→ * ID Prefix Strategy for Scannable Records
     3→ *
     4→ * Category     | Prefix | Example ID  | Purpose
     5→ * -------------|--------|-------------|--------------------
     6→ * Sales        | S-     | S-1001      | Customer Invoices
     7→ * Purchases    | P-     | P-1001      | Supplier Bills
     8→ * Customers    | C-     | C-101       | Party Master (Clients)
     9→ * Suppliers    | V-     | V-101       | Party Master (Vendors)
    10→ * Inventory    | I-     | I-101       | Product/Item Master
    11→ * Receipts     | REC-   | REC-101     | Money In (Payments Received)
    12→ * Payments     | PAY-   | PAY-101     | Money Out (Payments Made)
    13→ *
    14→ * FIX (High #4): ID counters are NO LONGER stored in localStorage as the
    15→ * primary source of truth. localStorage resets on every new device/browser
    16→ * session, causing duplicate IDs like "S-101" to collide with existing Firestore
    17→ * records. The new strategy:
    18→ *
    19→ *   1. The ManualEntryModal already fetches `ledger_entries` / `transactions` /
    20→ *      `inventory` on open and derives the max existing number from those records.
    21→ *      That Firestore-derived number is set into `formData.invoice_no` etc.
    22→ *
    23→ *   2. `getIDForEntry()` below is the LAST-RESORT fallback — used only when the
    24→ *      modal's async fetch hasn't completed yet, or for non-ledger entry types
    25→ *      (parties, inventory). It uses an in-memory counter seeded from a
    26→ *      conservative base that can be overridden at startup by calling
    27→ *      `seedCountersFromFirestore()` once the Firestore snapshot is available.
    28→ *
    29→ *   3. localStorage is still written as a within-session cache so rapid
    30→ *      consecutive creates on the same device don't repeat IDs before the
    31→ *      next Firestore open — but it is never the sole source of truth.
    32→ */
    33→
    34→let _currentUserId = '';
    35→const counterKey = (uid: string) => uid ? `app_id_counters_${uid}` : 'app_id_counters';
    36→
    37→interface IDCounters {
    38→  sales: number;
    39→  purchases: number;
    40→  customers: number;
    41→  suppliers: number;
    42→  inventory: number;
    43→  receipts: number;
    44→  payments: number;
    45→  waste: number;
    46→}
    47→
    48→const DEFAULT_COUNTERS: IDCounters = {
    49→  sales: 100,
    50→  purchases: 100,
    51→  customers: 100,
    52→  suppliers: 100,
    53→  inventory: 100,
    54→  receipts: 100,
    55→  payments: 100,
    56→  waste: 100,
    57→};
    58→
    59→// In-memory counters — authoritative during the current JS session.
    60→// Seeded from Firestore on first data load (see seedCountersFromFirestore).
    61→let _memCounters: IDCounters = { ...DEFAULT_COUNTERS };
    62→
    63→const readLocalCounters = (uid?: string): IDCounters | null => {
    64→  const key = counterKey(uid || _currentUserId);
    65→  try {
    66→    const stored = localStorage.getItem(key);
    67→    if (stored) return { ...DEFAULT_COUNTERS, ...JSON.parse(stored) };
    68→  } catch (_) {
    69→    try {
    70→      const stored = sessionStorage.getItem(key);
    71→      if (stored) return { ...DEFAULT_COUNTERS, ...JSON.parse(stored) };
    72→    } catch (__) { /* ignore */ }
    73→  }
    74→  return null;
    75→};
    76→
    77→const saveCounters = (counters: IDCounters): void => {
    78→  const key = counterKey(_currentUserId);
    79→  try {
    80→    localStorage.setItem(key, JSON.stringify(counters));
    81→  } catch (_) {
    82→    try {
    83→      sessionStorage.setItem(key, JSON.stringify(counters));
    84→    } catch (__) {
    85→      console.warn('ID counters: unable to persist counters, IDs may repeat on hard refresh');
    86→    }
    87→  }
    88→};
    89→
    90→/**
    91→ * Call this immediately after login with the authenticated user's UID.
    92→ * Switches the in-memory counter set to the correct user's namespace,
    93→ * preventing collisions between multiple users on the same device.
    94→ */
    95→export const initCountersForUser = (userId: string): void => {
    96→  if (!userId || userId === _currentUserId) return;
    97→  _currentUserId = userId;
    98→  const stored = readLocalCounters(userId);
    99→  if (stored) {
   100→    _memCounters = stored;
   101→  } else {
   102→    _memCounters = { ...DEFAULT_COUNTERS };
   103→  }
   104→};
   105→
   106→// Initialise in-memory counters from local storage (same-session cache).
   107→// Firestore-derived values can then upgrade these via seedCountersFromFirestore.
   108→const localCounters = readLocalCounters();
   109→if (localCounters) {
   110→  _memCounters = localCounters;
   111→}
   112→
   113→/**
   114→ * Call this ONCE after fetching existing records from Firestore so that the
   115→ * in-memory counters are always ≥ the highest ID already in the database.
   116→ * This is the primary defence against duplicate IDs across devices/sessions.
   117→ *
   118→ *@example
   119→ * const ledgerDocs = await ApiService.getAll(uid, 'ledger_entries');
   120→ * seedCountersFromFirestore(ledgerDocs.map(d => d.data().invoice_no), 'sales');
   121→ */
   122→export const seedCountersFromFirestore = (
   123→  existingIds: (string | number | undefined | null)[],
   124→  category: keyof IDCounters
   125→): void => {
   126→  const baseCount = Number(_memCounters[category]);
   127→  const expectedPrefix = PREFIX_MAP[category as IDCategory]; // e.g. "S-", "REC-"
   128→
   129→  const maxNum = existingIds.reduce<number>((max, raw) => {
   130→    if (raw == null || raw === '') return max;
   131→    const str = String(raw);
   132→
   133→    // Pure numeric IDs (legacy data) — accept as-is into the category.
   134→    if (/^\d+$/.test(str)) {
   135→      const n = parseInt(str, 10);
   136→      return !isNaN(n) && n > max ? n : max;
   137→    }
   138→
   139→    // Prefixed IDs — only accept if the prefix matches THIS category, so a
   140→    // stray "PAY-205" inside the sales collection can't push the sales counter.
   141→    if (expectedPrefix && !str.startsWith(expectedPrefix)) return max;
   142→
   143→    const digits = str.slice(expectedPrefix.length).replace(/[^0-9]/g, '');
   144→    if (!digits) return max;
   145→    const n = parseInt(digits, 10);
   146→    return !isNaN(n) && n > max ? n : max;
   147→  }, baseCount);
   148→
   149→  if (maxNum > _memCounters[category]) {
   150→    _memCounters[category] = maxNum;
   151→    saveCounters(_memCounters);
   152→  }
   153→};
   154→type IDCategory = 'sales' | 'purchases' | 'customers' | 'suppliers' | 'inventory' | 'receipts' | 'payments' | 'waste';
   155→
   156→const PREFIX_MAP: Record<IDCategory, string> = {
   157→  sales: 'S-',
   158→  purchases: 'P-',
   159→  customers: 'C-',
   160→  suppliers: 'V-',
   161→  inventory: 'I-',
   162→  receipts: 'REC-',
   163→  payments: 'PAY-',
   164→  waste: 'W-',
   165→};
   166→
   167→/**
   168→ * Generate a new prefixed ID for the given category.
   169→ * Uses the in-memory counter (seeded from Firestore when possible).
   170→ * @param category - The category type
   171→ * @returns A new unique ID like "S-101", "REC-102", etc.
   172→ */
   173→export const generatePrefixedID = (category: IDCategory): string => {
   174→  _memCounters[category] += 1;
   175→  saveCounters(_memCounters);
   176→  return `${PREFIX_MAP[category]}${_memCounters[category]}`;
   177→};
   178→
   179→/**
   180→ * Determine ID category based on entry type and context.
   181→ * @param type - The transaction or entry type
   182→ * @param role - Optional party role for party-specific IDs
   183→ */
   184→export const getIDForEntry = (
   185→  type: 'sell' | 'purchase' | 'received' | 'paid' | 'party' | 'inventory',
   186→  role?: 'customer' | 'supplier'
   187→): string => {
   188→  switch (type) {
   189→    case 'sell':      return generatePrefixedID('sales');
   190→    case 'purchase':  return generatePrefixedID('purchases');
   191→    case 'received':  return generatePrefixedID('receipts');
   192→    case 'paid':      return generatePrefixedID('payments');
   193→    case 'party':     return role === 'supplier'
   194→                        ? generatePrefixedID('suppliers')
   195→                        : generatePrefixedID('customers');
   196→    case 'inventory': return generatePrefixedID('inventory');
   197→    default:          return generatePrefixedID('sales');
   198→  }
   199→};
   200→
   201→/**
   202→ * Reset all in-memory and persisted counters back to 100 (next ID starts at 101).
   203→ * Only use this for testing / data wipes.
   204→ */
   205→export const resetAllCounters = (): void => {
   206→  _memCounters = { ...DEFAULT_COUNTERS };
   207→  saveCounters(_memCounters);
   208→};
   209→
   210→/**
   211→ * Parse a prefixed ID to extract category prefix and number.
   212→ * @param id - The prefixed ID like "S-101"
   213→ */
   214→export const parseID = (id: string): { prefix: string; number: number } | null => {
   215→  if (!id) return null;
   216→
   217→  // Strict form: "PREFIX-1234" (no trailing chars).
   218→  const strict = id.match(/^([A-Z]+-?)(\d+)$/);
   219→  if (strict) {
   220→    return { prefix: strict[1], number: parseInt(strict[2], 10) };
   221→  }
   222→
   223→  // Lenient fallback: any leading prefix followed by a digit run, with
   224→  // optional trailing characters (e.g. "S-101A", "INV-2024-001-rev").
   225→  // This prevents the seeder from silently dropping slightly-malformed IDs.
   226→  const lenient = id.match(/^([A-Z]+-?)(\d+)/);
   227→  if (lenient) {
   228→    return { prefix: lenient[1], number: parseInt(lenient[2], 10) };
   229→  }
   230→
   231→  // Pure numeric ID (legacy data with no prefix).
   232→  if (/^\d+$/.test(id)) {
   233→    return { prefix: '', number: parseInt(id, 10) };
   234→  }
   235→
   236→  return null;
   237→};
   238→
