    32→export const FactoryResetBinService = {
    33→  savePreResetSnapshot: async (uid: string): Promise<string> => {
    34→    const resetId = `reset_${Date.now()}`;
    35→    const now = new Date();
    36→    const expiresAt = new Date(now.getTime() + RETENTION_DAYS * 24 * 3600 * 1000);
    37→
    38→    const allData: Record<string, any[]> = {};
    39→    for (const colName of COLLECTIONS) {
    40→      const snap = await getDocs(collection(db, `users/${uid}/${colName}`));
    41→      allData[colName] = snap.docs.map(d => ({ id: d.id, ...d.data() }));
    42→    }
    43→
    44→    const totalItems = Object.values(allData).reduce((s, arr) => s + arr.length, 0);
    45→
    46→    await setDoc(doc(db, metaPath(uid), resetId), {
    47→      reset_id: resetId,
    48→      created_at: now.toISOString(),
    49→      expires_at: expiresAt.toISOString(),
    50→      total_items: totalItems,
    51→      collections: COLLECTIONS,
    52→    });
    53→
    54→    let batch = writeBatch(db);
    55→    let batchOps = 0;
    56→
    57→    for (const colName of COLLECTIONS) {
    58→      const items = allData[colName];
    59→      const numChunks = Math.max(1, Math.ceil(items.length / ITEMS_PER_CHUNK));
    60→      for (let c = 0; c < numChunks; c++) {
    61→        const chunk = items.slice(c * ITEMS_PER_CHUNK, (c + 1) * ITEMS_PER_CHUNK);
    62→        if (chunk.length === 0 && c > 0) break;
    63→        const chunkRef = doc(db, dataPath(uid), `${resetId}_${colName}_${c}`);
    64→        batch.set(chunkRef, {
    65→          reset_id: resetId,
    66→          collection: colName,
    67→          chunk: c,
    68→          items: chunk,
    69→        });
    70→        batchOps++;
    71→        if (batchOps >= MAX_BATCH_OPS) {
    72→          await batch.commit();
    73→          batch = writeBatch(db);
    74→          batchOps = 0;
    75→        }
    76→      }
    77→    }
    78→
    79→    if (batchOps > 0) await batch.commit();
    80→
    81→    return resetId;
    82→  },
    83→
    84→  listSnapshots: async (uid: string): Promise<any[]> => {
    85→    const snap = await getDocs(collection(db, metaPath(uid)));
    86→    const now = new Date();
    87→    return snap.docs
    88→      .map(d => ({ id: d.id, ...d.data() } as any))
    89→      .filter(s => new Date(s.expires_at) > now)
    90→      .sort((a, b) => b.created_at.localeCompare(a.created_at));
    91→  },
