    93→  restoreSnapshot: async (uid: string, resetId: string): Promise<void> => {
    94→    const dataSnap = await getDocs(collection(db, dataPath(uid)));
    95→    const chunks = dataSnap.docs
    96→      .filter(d => d.id.startsWith(`${resetId}_`))
    97→      .map(d => d.data() as any);
    98→
    99→    const reassembled: Record<string, any[]> = {};
   100→    for (const chunk of chunks) {
   101→      if (!reassembled[chunk.collection]) reassembled[chunk.collection] = [];
   102→      reassembled[chunk.collection].push(...(chunk.items || []));
   103→    }
   104→
   105→    const MAX_BATCH = 440;
   106→    let batch = writeBatch(db);
   107→    let opCount = 0;
   108→
   109→    for (const colName of COLLECTIONS) {
   110→      const items = reassembled[colName] || [];
   111→      for (const item of items) {
   112→        const docId = item.id || item._id;
   113→        const { id: _i1, _id: _i2, ...docData } = item;
   114→        const ref = docId
   115→          ? doc(db, 'users', uid, colName, docId)
   116→          : doc(collection(db, 'users', uid, colName));
   117→        batch.set(ref, docData);
   118→        opCount++;
   119→        if (opCount >= MAX_BATCH) {
   120→          await batch.commit();
   121→          batch = writeBatch(db);
   122→          opCount = 0;
   123→        }
   124→      }
   125→    }
   126→    if (opCount > 0) await batch.commit();
