     1→/**
     2→ * queryPersistStorage  — AsyncStorage-shaped IndexedDB wrapper for the React
     3→ * Query persister.
     4→ *
     5→ * Why IndexedDB (not localStorage):
     6→ *   • localStorage is a 5–10 MB hard cap and is synchronous, which blocks the
     7→ *     main thread on every read. A shopkeeper with thousands of items + months
     8→ *     of ledger entries would blow past that limit and stutter the UI.
     9→ *   • IndexedDB is async and effectively unbounded (browser quota — typically
    10→ *     hundreds of MB), perfect for full-collection caching of inventory,
    11→ *     parties, ledger, transactions, waste.
    12→ *
    13→ * We use `idb-keyval` (≈600 B gzipped) because the cache only ever stores ONE
    14→ * blob keyed by query-cache id — there's no need for a full schema or indexes.
    15→ * The `AsyncStorage` interface (`getItem`/`setItem`/`removeItem`) is exactly
    16→ * what `@tanstack/query-async-storage-persister` expects.
    17→ *
    18→ * Module 4 — Persisted State Recovery:
    19→ *   • Detects corrupted / unparseable blobs on getItem
    20→ *   • Auto-clears the corrupt entry so the app starts fresh rather than looping
    21→ *   • Guards against schema mismatches by validating the top-level structure
    22→ */
    23→
    24→import { get, set, del, createStore } from 'idb-keyval';
    25→import { errorLogger } from '../utils/errorLogger';
    26→
    27→// Dedicated DB + store so we don't clash with anything else the app might
    28→// stash in IndexedDB later (Capacitor plugins, Firebase persistence, etc.).
    29→const dbStore = createStore('shopkeeper-cache', 'react-query');
    30→
    31→// ── Cache integrity check ─────────────────────────────────────────────────────
    32→
    33→/**
    34→ * Lightweight structure validation for a dehydrated React Query cache blob.
    35→ * The persister stores JSON with a top-level `clientState` object.
    36→ * Returns false if the blob is clearly malformed.
    37→ */
    38→function isValidCacheBlob(raw: string): boolean {
    39→  try {
    40→    const parsed = JSON.parse(raw);
    41→    // React Query persister format: { clientState: { queries: [...] } }
    42→    if (typeof parsed !== 'object' || parsed === null) return false;
    43→    if ('clientState' in parsed) {
    44→      const cs = parsed.clientState;
    45→      if (typeof cs !== 'object' || cs === null) return false;
    46→      if ('queries' in cs && !Array.isArray(cs.queries)) return false;
    47→    }
    48→    return true;
    49→  } catch {
    50→    return false;
    51→  }
    52→}
    53→
    54→// ── Storage adapter ───────────────────────────────────────────────────────────
    55→
    56→export const indexedDBStorage = {
    57→  getItem: async (key: string): Promise<string | null> => {
    58→    try {
    59→      const value = await get<string>(key, dbStore);
    60→      if (value === undefined || value === null) return null;
    61→
    62→      // Module 4: validate the blob before handing it to the persister.
    63→      // A corrupted blob (truncated write, schema mismatch, etc.) would cause
    64→      // React Query to enter an error/loading loop.  Returning null forces a
    65→      // clean rebuild from Firebase instead.
    66→      if (typeof value === 'string' && !isValidCacheBlob(value)) {
    67→        errorLogger.log(
    68→          'storage',
    69→          new Error('React Query cache blob is malformed — clearing'),
    70→          { key },
    71→          'queryPersistStorage',
    72→        );
    73→        // Best-effort async clear; don't await to stay non-blocking
    74→        del(key, dbStore).catch(() => {});
    75→        return null;
    76→      }
    77→
    78→      return value;
    79→    } catch (e) {
    80→      // IDB can fail in private-mode Safari, locked-down browsers, storage
    81→      // quota exceeded, etc.  Returning null lets the persister skip
    82→      // rehydration gracefully and the app falls back to a fresh Firebase fetch.
    83→      errorLogger.log('storage', e, { key, op: 'get' }, 'queryPersistStorage');
    84→      return null;
    85→    }
    86→  },
    87→
    88→  setItem: async (key: string, value: string): Promise<void> => {
    89→    try {
    90→      // Don't bother persisting a clearly invalid blob
    91→      if (!value || typeof value !== 'string') return;
    92→      await set(key, value, dbStore);
    93→    } catch (e) {
    94→      errorLogger.log('storage', e, { key, op: 'set' }, 'queryPersistStorage');
    95→    }
    96→  },
    97→
    98→  removeItem: async (key: string): Promise<void> => {
    99→    try {
   100→      await del(key, dbStore);
   101→    } catch (e) {
   102→      errorLogger.log('storage', e, { key, op: 'remove' }, 'queryPersistStorage');
   103→    }
   104→  },
