     1→/**
     2→ * cacheGuard — Safe localStorage / IndexedDB hydration guards
     3→ *
     4→ * Protects against:
     5→ * • JSON parse failures on corrupted blobs
     6→ * • Schema mismatches after app updates
     7→ * • localStorage quota / SecurityError exceptions
     8→ * • Corrupted sync queue arrays
     9→ */
    10→
    11→import { errorLogger } from './errorLogger';
    12→
    13→// ── Safe JSON parse ───────────────────────────────────────────────────────────
    14→
    15→export function safeParse<T>(raw: string | null | undefined, fallback: T): T {
    16→  if (!raw || raw === 'undefined' || raw === 'null') return fallback;
    17→  try {
    18→    const v = JSON.parse(raw);
    19→    return (v === null || v === undefined) ? fallback : (v as T);
    20→  } catch {
    21→    return fallback;
    22→  }
    23→}
    24→
    25→// ── Safe localStorage ─────────────────────────────────────────────────────────
    26→
    27→export function safeLocalGet<T>(key: string, fallback: T): T {
    28→  try {
    29→    const raw = localStorage.getItem(key);
    30→    if (raw === null) return fallback;
    31→    if (typeof fallback === 'boolean')  return (raw === 'true') as unknown as T;
    32→    if (typeof fallback === 'number')   {
    33→      const n = Number(raw);
    34→      return isNaN(n) ? fallback : n as unknown as T;
    35→    }
    36→    if (typeof fallback === 'string')   return raw as unknown as T;
    37→    return safeParse(raw, fallback);
    38→  } catch (e) {
    39→    errorLogger.log('storage', e, { key }, 'cacheGuard');
    40→    return fallback;
    41→  }
    42→}
    43→
    44→export function safeLocalSet(key: string, value: unknown): boolean {
    45→  try {
    46→    localStorage.setItem(key, typeof value === 'string' ? value : JSON.stringify(value));
    47→    return true;
    48→  } catch (e) {
    49→    errorLogger.log('storage', e, { key }, 'cacheGuard');
    50→    return false;
    51→  }
    52→}
    53→
    54→export function safeLocalRemove(key: string): void {
    55→  try { localStorage.removeItem(key); } catch {}
    56→}
