    60→/** Returns true if the offline sync queue exists but is not a valid array */
    61→export function isQueueCorrupted(): boolean {
    62→  try {
    63→    const raw = localStorage.getItem('osync_queue_v3');
    64→    if (!raw) return false;
    65→    const q = JSON.parse(raw);
    66→    return !Array.isArray(q);
    67→  } catch {
