   150→export function searchContacts(contacts: AppContact[], query: string): AppContact[] {
   151→  if (!query || !query.trim()) return [];
   152→  const q       = query.toLowerCase().trim();
   153→  const qDigits = q.replace(/\D/g, '');
   154→
   155→  const startsWith = contacts.filter(c => c.name.toLowerCase().startsWith(q));
