   201→ * @param role - Optional party role for party-specific IDs
   202→ */
   203→export const getIDForEntry = (
   204→  type: 'sell' | 'purchase' | 'received' | 'paid' | 'party' | 'inventory',
   205→  role?: 'customer' | 'supplier'
   206→): string => {
   207→  switch (type) {
   208→    case 'sell':      return generatePrefixedID('sales');
   209→    case 'purchase':  return generatePrefixedID('purchases');
   210→    case 'received':  return generatePrefixedID('receipts');
   211→    case 'paid':      return generatePrefixedID('payments');
   212→    case 'party':     return role === 'supplier'
