   221→ * Reset all in-memory and persisted counters back to 100 (next ID starts at 101).
   222→ * Only use this for testing / data wipes.
   223→ */
   224→export const resetAllCounters = (): void => {
   225→  _memCounters = { ...DEFAULT_COUNTERS };
