   229→/**
   230→ * Parse a prefixed ID to extract category prefix and number.
   231→ * @param id - The prefixed ID like "S-101"
   232→ */
   233→export const parseID = (id: string): { prefix: string; number: number } | null => {
   234→  if (!id) return null;
   235→
   236→  // Strict form: "PREFIX-1234" (no trailing chars).
   237→  const strict = id.match(/^([A-Z]+-?)(\d+)$/);
   238→  if (strict) {
   239→    return { prefix: strict[1], number: parseInt(strict[2], 10) };
   240→  }
   241→
   242→  // Lenient fallback: any leading prefix followed by a digit run, with
   243→  // optional trailing characters (e.g. "S-101A", "INV-2024-001-rev").
   244→  // This prevents the seeder from silently dropping slightly-malformed IDs.
   245→  const lenient = id.match(/^([A-Z]+-?)(\d+)/);
   246→  if (lenient) {
   247→    return { prefix: lenient[1], number: parseInt(lenient[2], 10) };
   248→  }
   249→
   250→  // Pure numeric ID (legacy data with no prefix).
   251→  if (/^\d+$/.test(id)) {
   252→    return { prefix: '', number: parseInt(id, 10) };
   253→  }
   254→
   255→  return null;
   256→};
