     1→/**
     2→ * useScrollMemory(key)
     3→ *
     4→ * Attach to any scrollable element to automatically save and restore
     5→ * its scroll position when the screen is left and returned to.
     6→ *
     7→ * Usage:
     8→ *   const scrollRef = useScrollMemory('inventory');
     9→ *   return <div ref={scrollRef} className="flex-1 overflow-y-auto">...</div>;
    10→ *
    11→ * Restoration strategy — invisible by design:
    12→ *   useLayoutEffect runs synchronously after DOM mutations but BEFORE the
    13→ *   browser paints, so scrollTop is set to the saved value before the user
    14→ *   ever sees the page rendered at position 0.  A requestAnimationFrame
    15→ *   fallback re-applies the value on the next frame in case the layout was
    16→ *   not fully resolved (e.g. images still loading heights).
    17→ *
    18→ *   An additional 120 ms retry covers async-data views where content height
    19→ *   is shorter than the saved offset at the time of the first RAF.
    20→ *
    21→ * Save strategy:
    22→ *   • Throttled live-save every 400 ms while scrolling (survives fast unmounts).
    23→ *   • Final save on unmount — uses the closure-captured `el` reference, NOT
    24→ *     ref.current, because React 18 may have already set ref.current = null
    25→ *     before the async useEffect cleanup fires.
    26→ *
    27→ * Module 9
    28→ */
    29→
    30→import { useRef, useEffect, useLayoutEffect, MutableRefObject } from 'react';
    31→import { saveScrollPosition, getScrollPosition } from '../utils/scrollMemory';
    32→
    33→const THROTTLE_MS  = 400;
    34→const RETRY_DELAY  = 120;   // ms — retry restore for async-data views
    35→
    36→export function useScrollMemory(key: string): MutableRefObject<HTMLDivElement | null> {
    37→  const ref           = useRef<HTMLDivElement | null>(null);
    38→  const throttleTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
    39→  const rafRef        = useRef<number | null>(null);
    40→  const retryRef      = useRef<ReturnType<typeof setTimeout> | null>(null);
    41→  const prevKey       = useRef(key);
    42→
    43→  // ── Restore before first paint ────────────────────────────────────────────
    44→  useLayoutEffect(() => {
    45→    // Save position for the previous key if it changed mid-lifecycle
    46→    if (prevKey.current !== key) {
    47→      if (ref.current) saveScrollPosition(prevKey.current, ref.current.scrollTop);
    48→      prevKey.current = key;
    49→    }
    50→
    51→    const saved = getScrollPosition(key);
    52→    if (saved <= 0) return;
    53→
    54→    const applyScroll = () => {
    55→      if (ref.current) ref.current.scrollTop = saved;
    56→    };
    57→
    58→    applyScroll();
    59→
    60→    // RAF fallback: re-apply after layout heights finalise
    61→    rafRef.current = requestAnimationFrame(() => {
    62→      applyScroll();
    63→      rafRef.current = null;
    64→    });
    65→
    66→    // Retry fallback: covers async-data views where content loads after mount
    67→    retryRef.current = setTimeout(() => {
    68→      applyScroll();
    69→      retryRef.current = null;
    70→    }, RETRY_DELAY);
    71→
    72→    return () => {
    73→      if (rafRef.current)   { cancelAnimationFrame(rafRef.current); rafRef.current = null; }
    74→      if (retryRef.current) { clearTimeout(retryRef.current);       retryRef.current = null; }
    75→    };
    76→  }, [key]);
    77→
    78→  // ── Throttled live-save + final save on unmount ───────────────────────────
    79→  useEffect(() => {
    80→    const el = ref.current;
    81→    if (!el) return;
    82→
    83→    const onScroll = () => {
    84→      if (throttleTimer.current) return;
    85→      throttleTimer.current = setTimeout(() => {
    86→        // Use 'el' (captured in closure) — ref.current may be null after unmount
    87→        saveScrollPosition(key, el.scrollTop);
    88→        throttleTimer.current = null;
    89→      }, THROTTLE_MS);
    90→    };
    91→
    92→    el.addEventListener('scroll', onScroll, { passive: true });
    93→
    94→    return () => {
    95→      el.removeEventListener('scroll', onScroll);
    96→      if (throttleTimer.current) {
    97→        clearTimeout(throttleTimer.current);
    98→        throttleTimer.current = null;
    99→      }
   100→      // Final save — use 'el' (closure-captured), NOT ref.current which may
   101→      // already be null in React 18 concurrent-mode unmount ordering.
   102→      saveScrollPosition(key, el.scrollTop);
   103→    };
   104→  // eslint-disable-next-line react-hooks/exhaustive-deps
   105→  }, [key]);
   106→
   107→  return ref;
   108→}
